+@test "state: resolve target home accepts dotted fallback usernames" {
+    unset ACFS_HOME
+    unset ACFS_STATE_FILE
+    export TARGET_HOME=""
+    export TARGET_USER="john.doe"
+    export HOME="/"
+
+    getent() {
